}

.widget-header {
    margin-bottom: 15px;
}

.widget-title {
    font-size: 16px;
    font-weight: 600;
    color: #003d4d;
    display: flex;
    align-items: center;
    gap: 8px;
}

.widget-title i {
    color: #006666;
}

.chart-container {
    min-height: 400px;
    width: 100%;
}

.loading {
    text-align: center;
    padding: 40px;
    color: #7f8c8d;
}
</style>
