<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white">
    <div class="widget-header graph-widget-heading float-left w-100">
      <div class="widget-title">
        <i class="fas fa-receipt"></i> Avg Bill Amount
      </div>
    </div>
    
    <div v-if="loading" class="loading">Loading...</div>
    <div v-else id="avgBillChart" class="chart-container"></div>
    
    <div class="mini-stats">
      <div class="mini-stat">
        <div class="mini-stat-value">{{ MaxAvgBill }}</div>
        <div class="mini-stat-label">Max Avg Bill</div>
      </div>
      <div class="mini-stat">
        <div class="mini-stat-value">{{ MedianAvgBill }}</div>
        <div class="mini-stat-label">Median Avg Bill</div>
      </div>
    </div>
  </div>
</template>

<script>
import { analyticsService } from '../../../../services/analyticsService';
import * as Plotly from 'plotly.js-dist';

export default {
  name: 'AvgBillAmountWidget',
  data() {
    return {
      loading: false,
      stats: null
    };
  },
  mounted() {
    this.loadData();
  },
   props: {
    QuarterlyTrendAnalysisData: {
      type: Array,
      default: () => []
    },
    MaxAvgBill: {
      type: Number,
      
    },MedianAvgBill: {
      type: Number,
     
    }
  },
  methods: {
    async loadData() {
      //debugger
      var vm = this;
      vm.loading = true;
      try {
        vm.quarters = vm.QuarterlyTrendAnalysisData.map(d => d.Quarter_Label);
        vm.revenues = vm.QuarterlyTrendAnalysisData.map(d => d.Average_Bill_Amount);
        vm.drawChart();

      } catch (error) {
        console.error('Error loading total revenue trend:', error);
      } finally {
        vm.loading = false;
      }
    }, 
    drawChart(data) {
      //if (!data || !data.quarters || !data.values) return;
      
      const trace = {
        x: this.quarters,
        y: this.values,
        type: 'bar',
        marker: { color: '#8b5cf6' }
      };
      
      const layout = {
        margin: { t: 30, b: 60, l: 50, r: 30 },
        paper_bgcolor: 'transparent',
        plot_bgcolor: 'transparent',
        height: 280
      };
      
      Plotly.newPlot('avgBillChart', [trace], layout, { responsive: true });
    }
  }
};
</script>

