<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white">
    <div class="widget-header graph-widget-heading float-left w-100">
      <div class="widget-title">
        <i class="fas fa-chart-bar"></i> Yearly Revenue Bar
      </div>
    </div>
    
    <div v-if="loading" class="loading">Loading...</div>
    <div v-else id="yearlyRevenueChart" class="chart-container"></div>
    
    <div class="mini-stats">
      <div class="mini-stat">
        <div class="mini-stat-value">{{ BestYear.year }}</div>
        <div class="mini-stat-label">Best Year (Revenue)</div>
      </div>
      <div class="mini-stat">
        <div class="mini-stat-value">{{ YearlyGrowth }}</div>
        <div class="mini-stat-label">Growth</div>
      </div>
    </div>
  </div>
</template>

<script>
import { analyticsService } from '../../../../services/analyticsService';
import * as Plotly from 'plotly.js-dist';

export default {
  name: 'YearlyRevenueWidget',
  data() {
    return {
      loading: false,
      stats: null
    };
  },
  mounted() {
    this.loadData();
  },
  props: {
    QuarterlyTrendAnalysisData: {
      type: Array,
      default: () => []
    },
    BestYear: {
      type: Object,
      default: () => ({ year: null, revenue: null })
    },
    YearlyGrowth: {
      type: [String, Number],
      default: null
    }
  },
  methods: {
    async loadData() {
      var vm = this;
      vm.loading = true;
      try {
        // vm.quarters = vm.QuarterlyTrendAnalysisData.map(d => d.Year);
        // vm.revenues = vm.QuarterlyTrendAnalysisData.map(d =>
        //   Math.round(d.Total_Revenue)
        // );
        const yearlyData = {};
        vm.QuarterlyTrendAnalysisData.forEach(d => {
          if (!yearlyData[d.Year]) {
            yearlyData[d.Year] = 0;
          }
          yearlyData[d.Year] += d.Total_Revenue;
        });
        // sorted years
        vm.years = Object.keys(yearlyData).sort();

        // rounded yearly revenues
        vm.values = vm.years.map(year =>
          Math.round(yearlyData[year])
        );
        vm.drawChart();

      } catch (error) {
        console.error('Error loading total revenue trend:', error);
      } finally {
        vm.loading = false;
      }
    }, 
    drawChart() {
      //if (!data || !data.years || !data.values) return;
      
      const trace = {
        x: this.years,
        y: this.values,
        type: 'bar',
        marker: { color: '#14b8a6' }
      };
      
      const layout = {
        margin: { t: 30, b: 30, l: 50, r: 30 },
        paper_bgcolor: 'transparent',
        plot_bgcolor: 'transparent',
        height: 280
      };
      
      Plotly.newPlot('yearlyRevenueChart', [trace], layout, { responsive: true });
    }
  }
};
</script>

